<?php require_once 'db.php'; verify_csrf(); $msg=$err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $name=trim($_POST['name']??''); $email=filter_input(INPUT_POST,'email',FILTER_VALIDATE_EMAIL); $pass=$_POST['password']??''; if(strlen($name)<2||!$email||strlen($pass)<6) $err='Enter valid name, email, and 6+ character password.'; else try{ $role=pdo()->query("SELECT id FROM roles WHERE name='student'")->fetchColumn(); pdo()->beginTransaction(); pdo()->prepare('INSERT INTO users(role_id,name,email,password,phone) VALUES(?,?,?,?,?)')->execute([$role,$name,$email,password_hash($pass,PASSWORD_DEFAULT),trim($_POST['phone']??'')]); $uid=pdo()->lastInsertId(); pdo()->prepare('INSERT INTO students(user_id,roll_no,course) VALUES(?,?,?)')->execute([$uid,trim($_POST['roll_no']??''),trim($_POST['course']??'')]); pdo()->commit(); $msg='Registration successful. Please login.'; }catch(Throwable $e){ if(pdo()->inTransaction()) pdo()->rollBack(); $err='Email already exists or invalid data.'; }} app_header('Register'); ?>
<section class="auth card"><h1>Student Registration</h1><p class="ok"><?=e($msg)?></p><p class="error"><?=e($err)?></p><form method="post"><?=csrf_field()?><input name="name" placeholder="Full name" required><input name="email" type="email" placeholder="Email" required><input name="phone" placeholder="Phone"><input name="roll_no" placeholder="Roll number"><input name="course" placeholder="Course"><input name="password" type="password" placeholder="Password" required><button class="btn">Create account</button></form></section><?php app_footer(); ?>
